// components/ChatbotInterface.jsx - COMPLETE FIXED VERSION
import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './ERPChatBot.css'; // We'll create this CSS file

// ✅ Create axios instance with base URL
const api = axios.create({
  baseURL: 'http://localhost:65000', // Your backend URL
  withCredentials: true, // CRITICAL for session cookies
  timeout: 15000 // 15 second timeout
});

const ChatbotInterface = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [isCheckingAuth, setIsCheckingAuth] = useState(true);
  const [connectionError, setConnectionError] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Initialize on component mount
  useEffect(() => {
    checkAuthAndLoadMessages();
    
    // Load session ID from localStorage
    const savedSessionId = localStorage.getItem('chatbotSessionId');
    if (savedSessionId) {
      setSessionId(savedSessionId);
    }
    
    // Load messages from localStorage
    const savedMessages = localStorage.getItem('chatbot_messages');
    if (savedMessages) {
      try {
        const parsed = JSON.parse(savedMessages);
        if (Array.isArray(parsed)) {
          // Keep only last 15 messages
          const recentMessages = parsed.slice(-15);
          setMessages(recentMessages);
          
          // Auto-open if there are unread messages from bot
          const lastMsg = recentMessages[recentMessages.length - 1];
          if (lastMsg && lastMsg.sender === 'bot') {
            setIsOpen(true);
          }
        }
      } catch (e) {
        console.error('Error loading saved messages:', e);
        localStorage.removeItem('chatbot_messages');
      }
    }
  }, []);

  // Auto-scroll to bottom
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Save messages to localStorage
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('chatbot_messages', JSON.stringify(messages));
    }
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // ✅ Check authentication and load user info
  const checkAuthAndLoadMessages = async () => {
    try {
      setIsCheckingAuth(true);
      setConnectionError(false);
      
      // First try to get user info from auth endpoint
      const response = await api.get('/api/auth/me');
      
      if (response.data && response.data.user) {
        const userData = response.data.user;
        const userInfoObj = {
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username || 'unknown',
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName,
          profilePic: userData.profilePic
        };
        
        setUserInfo(userInfoObj);
        localStorage.setItem('userInfo', JSON.stringify(userInfoObj));
        
        console.log('✅ User authenticated:', userInfoObj.role, userInfoObj.studentId);
        
        // Check chatbot status
        try {
          const statusRes = await api.get('/api/chatbot/status');
          console.log('Chatbot status:', statusRes.data);
        } catch (statusErr) {
          console.log('Chatbot status check note:', statusErr.message);
        }
        
        // Send greeting message if it's a new session
        if (messages.length === 0) {
          setTimeout(() => {
            if (userInfoObj.role === 'student') {
              addSystemMessage(`Hello ${userInfoObj.firstName || 'Student'}! I'm your ERP Assistant. How can I help you today?`);
            }
          }, 500);
        }
      }
    } catch (error) {
      console.log('Auth check failed:', error.message);
      
      // Try fallback to localStorage
      try {
        const stored = localStorage.getItem('userInfo');
        if (stored) {
          const userData = JSON.parse(stored);
          if (userData && userData.role === 'student') {
            setUserInfo({
              id: userData._id,
              role: userData.role,
              studentId: userData.studentId || userData.username,
              email: userData.email || userData.universityEmail,
              name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
              firstName: userData.firstName
            });
            console.log('🔄 Using cached user info');
            return;
          }
        }
        
        setUserInfo(null);
        setConnectionError(true);
        
        // Show connection error message
        if (messages.length === 0) {
          addSystemMessage("Unable to connect to authentication service. Please refresh the page or login again.");
        }
      } catch (parseError) {
        console.error('Error parsing stored user info:', parseError);
        localStorage.removeItem('userInfo');
      }
    } finally {
      setIsCheckingAuth(false);
    }
  };

  // ✅ Handle send message
  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim() || isLoading || !userInfo || userInfo.role !== 'student') return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message to chat
    const newUserMessage = {
      id: Date.now(),
      text: userMessage,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    try {
      console.log('📤 Sending to chatbot:', { 
        studentId: userInfo.studentId,
        message: userMessage,
        sessionId: sessionId 
      });
      
      const response = await api.post('/api/chatbot/chat', {
        message: userMessage,
        sessionId: sessionId
      });

      console.log('📥 Chatbot response:', response.data);

      if (response.data.success) {
        // Update session ID if new one provided
        if (response.data.sessionId && response.data.sessionId !== sessionId) {
          setSessionId(response.data.sessionId);
          localStorage.setItem('chatbotSessionId', response.data.sessionId);
        }

        // Add bot response
        const botMessage = {
          id: Date.now() + 1,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          metadata: response.data.metadata
        };
        
        setMessages(prev => [...prev, botMessage]);
        setConnectionError(false);
      } else {
        // Handle chatbot error
        addErrorMessage(response.data.message || "The chatbot couldn't process your request.");
      }
    } catch (error) {
      console.error('❌ Chat error:', {
        message: error.message,
        status: error.response?.status,
        data: error.response?.data
      });
      
      let errorText = "Sorry, I'm having trouble connecting to the chatbot.";
      
      if (error.response) {
        switch (error.response.status) {
          case 401:
            errorText = "Your session has expired. Please refresh the page and log in again.";
            setUserInfo(null);
            localStorage.removeItem('userInfo');
            break;
          case 403:
            errorText = "Chatbot is only available for students. Please login with a student account.";
            break;
          case 429:
            errorText = "Too many requests. Please wait a moment before trying again.";
            break;
          case 500:
            errorText = "Server error. Please try again in a few moments.";
            break;
          default:
            errorText = error.response.data?.message || "Something went wrong. Please try again.";
        }
      } else if (error.request) {
        errorText = "Cannot connect to the server. Please check your internet connection.";
        setConnectionError(true);
      } else {
        errorText = "An unexpected error occurred. Please try again.";
      }
      
      addErrorMessage(errorText);
    } finally {
      setIsLoading(false);
      // Focus input after a short delay
      setTimeout(() => {
        if (inputRef.current) {
          inputRef.current.focus();
        }
      }, 100);
    }
  };

  const addErrorMessage = (text) => {
    const errorMessage = {
      id: Date.now() + 1,
      text: text,
      sender: 'system',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      isError: true
    };
    setMessages(prev => [...prev, errorMessage]);
  };

  const addSystemMessage = (text) => {
    const systemMessage = {
      id: Date.now(),
      text: text,
      sender: 'system',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setMessages(prev => [...prev, systemMessage]);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage(e);
    }
  };

  const handleClearChat = () => {
    if (window.confirm('Are you sure you want to clear all chat history? This cannot be undone.')) {
      setMessages([]);
      setSessionId(null);
      localStorage.removeItem('chatbot_messages');
      localStorage.removeItem('chatbotSessionId');
      
      // Add a fresh greeting
      if (userInfo && userInfo.role === 'student') {
        setTimeout(() => {
          addSystemMessage(`Hello ${userInfo.firstName || 'Student'}! Chat cleared. How can I help you today?`);
        }, 300);
      } else {
        addSystemMessage("Chat cleared. Please login to start a new conversation.");
      }
    }
  };

  const handleQuickAction = (text) => {
    if (!userInfo || userInfo.role !== 'student') {
      addSystemMessage("Please login as a student to use quick actions.");
      return;
    }
    
    setInputMessage(text);
    // Auto-send after a short delay
    setTimeout(() => {
      if (inputMessage === text) {
        handleSendMessage({ preventDefault: () => {} });
      }
    }, 300);
  };

  const refreshAuth = async () => {
    setIsCheckingAuth(true);
    await checkAuthAndLoadMessages();
    addSystemMessage("Authentication status refreshed.");
  };

  const openChatbot = () => {
    setIsOpen(true);
    // Focus input after opening
    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
      }
    }, 300);
  };

  const closeChatbot = () => {
    setIsOpen(false);
  };

  // Quick action examples
  const quickActions = [
    { text: "What's my current fee due?", icon: "💰", color: "#10B981" },
    { text: "Show my attendance in current courses", icon: "📊", color: "#3B82F6" },
    { text: "What's my today's timetable?", icon: "📅", color: "#8B5CF6" },
    { text: "Show my last semester results", icon: "📝", color: "#EF4444" },
    { text: "Any upcoming university events?", icon: "🎉", color: "#F59E0B" },
    { text: "What courses am I taking this semester?", icon: "📚", color: "#6366F1" }
  ];

  // Show loading while checking auth
  if (isCheckingAuth && !isOpen) {
    return (
      <button 
        className="chatbot-icon"
        style={{ background: '#6B7280', cursor: 'wait' }}
        onClick={openChatbot}
        aria-label="Checking authentication..."
      >
        <div className="chatbot-icon-inner">
          <div className="spinner-small"></div>
        </div>
      </button>
    );
  }

  const isLoggedIn = userInfo && userInfo.role === 'student';

  return (
    <>
      {/* Chatbot Floating Icon */}
      {!isOpen && (
        <button 
          className="chatbot-icon"
          onClick={openChatbot}
          aria-label="Open ERP Assistant"
          style={{ 
            background: isLoggedIn ? 
              'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' : 
              connectionError ? '#EF4444' : '#9CA3AF'
          }}
          title={isLoggedIn ? "Open ERP Assistant" : "Login required to use chatbot"}
        >
          <div className="chatbot-icon-inner">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M12 2C6.48 2 2 6.48 2 12C2 17.52 6.48 22 12 22C17.52 22 22 17.52 22 12C22 6.48 17.52 2 12 2ZM12 20C7.59 20 4 16.41 4 12C4 7.59 7.59 4 12 4C16.41 4 20 7.59 20 12C20 16.41 16.41 20 12 20Z" fill="white"/>
              <path d="M11 11H13V17H11V11ZM11 7H13V9H11V7Z" fill="white"/>
            </svg>
            <span className="chatbot-icon-badge">
              {isLoggedIn ? "💬" : connectionError ? "⚠️" : "🔒"}
            </span>
          </div>
        </button>
      )}

      {/* Chatbot Window */}
      {isOpen && (
        <div className="chatbot-window">
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-header-content">
              <div className="chatbot-avatar">
                <span>🤖</span>
              </div>
              <div className="chatbot-header-text">
                <h3>ERP Assistant</h3>
                <p className="chatbot-status">
                  <span className={`status-dot ${isLoggedIn ? 'online' : 'offline'}`}></span>
                  {isLoading ? 'Typing...' : isLoggedIn ? 'Online • Ready to help' : 'Offline • Login required'}
                  {isLoggedIn && userInfo.studentId && (
                    <span className="chatbot-user-id"> • ID: {userInfo.studentId}</span>
                  )}
                </p>
              </div>
            </div>
            <div className="chatbot-header-actions">
              {!isLoggedIn && (
                <button 
                  className="refresh-btn"
                  onClick={refreshAuth}
                  title="Check login status"
                >
                  ↻
                </button>
              )}
              <button 
                className="chatbot-close-btn"
                onClick={closeChatbot}
                aria-label="Close chatbot"
              >
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
                </svg>
              </button>
            </div>
          </div>

          {/* Messages Container */}
          <div className="chatbot-messages">
            {messages.length === 0 ? (
              <div className="chatbot-welcome">
                <div className="welcome-avatar">
                  <span>🤖</span>
                </div>
                <h3>Hello{isLoggedIn && userInfo.firstName ? ` ${userInfo.firstName}` : ''}!</h3>
                <p>I'm your ERP Assistant. I can help you with:</p>
                
                <div className="welcome-features">
                  <ul>
                    <li>💰 <strong>Fees & Payments</strong> - Check due amounts, payment history</li>
                    <li>📊 <strong>Attendance</strong> - View attendance percentage by course</li>
                    <li>📅 <strong>Timetable</strong> - Daily/weekly schedule, class timings</li>
                    <li>📝 <strong>Exam Results</strong> - Semester grades, GPA/CGPA</li>
                    <li>🎉 <strong>Events</strong> - University events, holidays, deadlines</li>
                    <li>📚 <strong>Courses</strong> - Enrolled courses, faculty details</li>
                  </ul>
                </div>
                
                <div className="quick-actions-section">
                  <p className="quick-actions-title">Try asking:</p>
                  <div className="quick-actions-grid">
                    {quickActions.map((action, index) => (
                      <button
                        key={index}
                        className="quick-action-btn"
                        onClick={() => handleQuickAction(action.text)}
                        disabled={!isLoggedIn}
                        style={{ 
                          '--btn-color': action.color,
                          opacity: isLoggedIn ? 1 : 0.6,
                          cursor: isLoggedIn ? 'pointer' : 'not-allowed'
                        }}
                        title={isLoggedIn ? action.text : "Please login first"}
                      >
                        <span className="quick-action-icon" style={{ color: action.color }}>
                          {action.icon}
                        </span>
                        <span className="quick-action-text">{action.text}</span>
                      </button>
                    ))}
                  </div>
                </div>
                
                {!isLoggedIn && (
                  <div className="login-prompt">
                    <div className="login-icon">🔒</div>
                    <p className="login-message">You need to be logged in as a student to ask questions about your personal data.</p>
                    <div className="login-actions">
                      <button 
                        className="login-btn"
                        onClick={() => window.location.href = '/login'}
                      >
                        Go to Login
                      </button>
                      <button 
                        className="refresh-btn-small"
                        onClick={refreshAuth}
                      >
                        Check Status
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              messages.map((message) => (
                <div
                  key={message.id}
                  className={`message ${message.sender} ${message.isError ? 'error' : ''}`}
                >
                  {message.sender === 'bot' && (
                    <div className="message-avatar">🤖</div>
                  )}
                  {message.sender === 'system' && (
                    <div className="message-avatar">ℹ️</div>
                  )}
                  <div className="message-content">
                    <div className="message-text">
                      {message.text.split('\n').map((line, i) => (
                        <React.Fragment key={i}>
                          {line}
                          {i < message.text.split('\n').length - 1 && <br />}
                        </React.Fragment>
                      ))}
                    </div>
                    <div className="message-footer">
                      <div className="message-timestamp">
                        {message.timestamp}
                      </div>
                      {message.metadata?.intent && (
                        <div className="message-intent">
                          {message.metadata.intent}
                        </div>
                      )}
                    </div>
                  </div>
                  {message.sender === 'user' && (
                    <div className="message-avatar user-avatar">👤</div>
                  )}
                </div>
              ))
            )}
            
            {isLoading && (
              <div className="message bot">
                <div className="message-avatar">🤖</div>
                <div className="message-content">
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <form className="chatbot-input-area" onSubmit={handleSendMessage}>
            <div className="input-wrapper">
              <textarea
                ref={inputRef}
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={isLoggedIn ? 
                  "Ask about fees, attendance, timetable, results..." : 
                  "Please login as a student to ask questions"}
                rows="1"
                disabled={isLoading || !isLoggedIn}
                autoFocus={isLoggedIn}
              />
              <button 
                type="submit" 
                className="send-btn"
                disabled={!inputMessage.trim() || isLoading || !isLoggedIn}
                title={!isLoggedIn ? "Login required" : inputMessage.trim() ? "Send message" : "Type a message"}
              >
                {isLoading ? (
                  <div className="spinner"></div>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M2.01 21L23 12L2.01 3L2 10L17 12L2 14L2.01 21Z" fill="currentColor"/>
                  </svg>
                )}
              </button>
            </div>
            
            <div className="chatbot-footer">
              <button 
                type="button" 
                className="footer-btn"
                onClick={handleClearChat}
                title="Clear chat history"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
                </svg>
                Clear Chat
              </button>
              
              <div className="user-info">
                {isLoggedIn ? (
                  <>
                    <span className="user-role">{userInfo.role}</span>
                    {userInfo.studentId && (
                      <span className="user-id">{userInfo.studentId}</span>
                    )}
                    <button 
                      className="refresh-btn-tiny"
                      onClick={refreshAuth}
                      title="Refresh authentication"
                    >
                      ↻
                    </button>
                  </>
                ) : (
                  <>
                    <span className="user-not-logged">Not logged in</span>
                    <button 
                      className="refresh-btn-tiny"
                      onClick={refreshAuth}
                      title="Check login status"
                    >
                      ↻
                    </button>
                  </>
                )}
              </div>
              
              <div className="hint-text">
                {isLoggedIn ? "Press Enter to send • Shift+Enter for new line" : "Login required"}
              </div>
            </div>
          </form>
        </div>
      )}
    </>
  );
};

export default ChatbotInterface;
